import globimport pandas as pdimport numpy as np# list all data files from target folders''' please add folders paths below '''stroop_folders = [r'D:/PhD/study1/executive-function-tasks/Inhibition-Stroop/Adaptive/data',                  r'D:/PhD/study1/executive-function-tasks/Inhibition-Stroop/Standard/data',                  r'D:/PhD/study1/executive-function-tasks/Inhibition-Stroop/Control/data']stroop_fileslist = [file for path in stroop_folders for file in glob.glob(path + '/*.csv')]# create an empty list for storing datadata_list = []# create the for loop to go through all data filesfor files in range(0, len(stroop_fileslist)):    stroop = pd.read_csv(stroop_fileslist[files])    # create if condition to work with the data    if 'myExp.trial' in stroop.columns:        # create variables for numbers of congruent/incongruent/total trials for future calculation        congruent_num = len(stroop[stroop['myExp.congruent'] == 1])        incongruent_num = len(stroop[stroop['myExp.congruent'] == 0])        total_trials = stroop['myExp.trial'].max()        correctTrials_all = stroop['myExp.RT_correctTrials']        correctTrials_congruent = stroop.loc[(stroop['myExp.congruent'] == 1), 'myExp.RT_correctTrials']        correctTrials_incongruent = stroop.loc[(stroop['myExp.congruent'] == 0), 'myExp.RT_correctTrials']        # create mean RT variables        medianRT_correct_all = correctTrials_all.median() * 1000        medianRT_correct_congruent = correctTrials_congruent.median() * 1000        medianRT_correct_incongruent = correctTrials_incongruent.median() * 1000        medianRT_diff = medianRT_correct_incongruent - medianRT_correct_congruent        # create accuracy variables        accuracy_all = (stroop['myExp.Accuracy'].sum()/total_trials) * 100        accuracy_congruent = (stroop.loc[(stroop['myExp.congruent'] == 1), 'myExp.Accuracy'].sum() / congruent_num) * 100        accuracy_incongruent = (stroop.loc[(stroop['myExp.congruent'] == 0), 'myExp.Accuracy'].sum() / incongruent_num) * 100        # create trial duration variables        median_trial_duration = stroop['myExp.trialDuration'].median() * 1000        # creat completion time variable        completion_time = stroop['blank.stopped'].max() - stroop['experimentalTrial.started'].min()    else:        medianRT_correct_all = medianRT_correct_congruent = medianRT_correct_incongruent = medianRT_diff = \            accuracy_all = accuracy_congruent = accuracy_incongruent = median_trial_duration = None    # append values into the list    data_list.append({'participant': stroop.iloc[1]['participant'],                      'task': stroop.iloc[1]['expName'],                      'medianRT_correct_all(ms)': medianRT_correct_all,                      'medianRT_correct_congruent(ms)': medianRT_correct_congruent,                      'medianRT_correct_incongruent(ms)': medianRT_correct_incongruent,                      'medianRT_diff(ms)': medianRT_diff,                      'accuracy_all(%)': accuracy_all,                      'accuracy_congruent(%)': accuracy_congruent,                      'accuracy_incongruent(%)': accuracy_incongruent,                      'median_trialDuration(ms)': median_trial_duration,                      'completion_time(s)': completion_time})stroop_data_long = pd.DataFrame(data_list)# save as csvstroop_data_long.to_csv("stroop_longFormat.csv", index=False)